targets.rawSql:
SELECT open AS latest_open
FROM dashboard.futures_klines_${interval}
WHERE open IS NOT NULL
ORDER BY close_time DESC
LIMIT 1;

SELECT high AS latest_high
FROM dashboard.futures_klines_${interval}
WHERE high IS NOT NULL
ORDER BY close_time DESC
LIMIT 1;

SELECT low AS latest_low
FROM dashboard.futures_klines_${interval}
WHERE low IS NOT NULL
ORDER BY close_time DESC
LIMIT 1;

SELECT close AS latest_close
FROM dashboard.futures_klines_${interval}
WHERE close IS NOT NULL
ORDER BY close_time DESC
LIMIT 1;

SELECT close_time AS time, open, high, low, close
FROM dashboard.futures_klines_${interval}
WHERE $__timeFilter(close_time)
ORDER BY close_time;

SELECT
  create_time AS time,
  sum_taker_long_short_vol_ratio AS "Taker Buy/Sell Volume Ratio"
FROM dashboard.futures_metrics_${metrics_interval}
WHERE $__timeFilter(create_time)
ORDER BY create_time;
